body.script:
const state = { products: [], allProducts: [], categories: [], selectedCategory: '', searchTerm: '', orderLines: [], currentMethod: 'cash' };

async function initPos() {
    await loadProducts();
    renderProducts();
    renderCategories();
    document.getElementById('posUserInfo').textContent = 'Online';
}

async function loadProducts() {
    try {
        const resp = await fetch('/pos_lite/api/products', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: '{}' });
        const data = await resp.json();
        if (data.success) {
            state.allProducts = data.products;
            state.products = data.products;
            const cats = new Set();
            data.products.forEach(p => { const c = p.categ_id ? (Array.isArray(p.categ_id) ? p.categ_id[1] : p.categ_id) : 'Uncategorized'; cats.add(c); });
            state.categories = Array.from(cats).sort();
        }
    } catch (e) { showToast('Failed to load products', 'error'); }
}

function renderCategories() {
    const el = document.getElementById('posCategories');
    let html = '<button class="pos-cat-btn active" data-cat="" onclick="selectCategory(this, \'\')">All</button>';
    state.categories.forEach(c => { html += '<button class="pos-cat-btn" data-cat="' + escapeHtml(c) + '" onclick="selectCategory(this, \'' + escapeHtml(c) + '\')">' + escapeHtml(c) + '</button>'; });
    el.innerHTML = html;
}

function selectCategory(btn, cat) {
    document.querySelectorAll('.pos-cat-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    state.selectedCategory = cat;
    filterProducts();
}

function filterProducts() {
    const term = document.getElementById('posSearch').value.toLowerCase();
    let filtered = state.allProducts;
    if (term) filtered = filtered.filter(p => (p.name && p.name.toLowerCase().includes(term)) || (p.default_code && p.default_code.toLowerCase().includes(term)) || (p.barcode && p.barcode.toLowerCase().includes(term)));
    if (state.selectedCategory) filtered = filtered.filter(p => { const c = p.categ_id ? (Array.isArray(p.categ_id) ? p.categ_id[1] : p.categ_id) : 'Uncategorized'; return c === state.selectedCategory; });
    state.products = filtered;
    renderProducts();
}

function renderProducts() {
    const el = document.getElementById('posProducts');
    if (state.products.length === 0) { el.innerHTML = '<div class="pos-no-products"><svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>No products found</div>'; return; }
    let html = '';
    state.products.forEach(p => {
        const price = typeof p.list_price === 'number' ? p.list_price.toFixed(2) : '0.00';
        const code = p.default_code ? '<div class="pos-product-code">' + escapeHtml(p.default_code) + '</div>' : '';
        html += '<div class="pos-product-card" onclick="addProduct(' + p.id + ', \'' + escapeHtml(p.name) + '\', ' + p.list_price + ', \'' + escapeHtml(p.default_code || '') + '\')"><div class="pos-product-name">' + escapeHtml(p.name) + '</div>' + code + '<div class="pos-product-price">$' + price + '</div></div>';
    });
    el.innerHTML = html;
}

function addProduct(id, name, price, code) {
    const existing = state.orderLines.find(l => l.productId === id);
    if (existing) existing.qty += 1;
    else state.orderLines.push({ productId: id, name, price, code: code || '', qty: 1 });
    renderOrder(); updateTotals();
}

function changeQty(id, delta) {
    const line = state.orderLines.find(l => l.productId === id);
    if (!line) return;
    line.qty += delta;
    if (line.qty <= 0) state.orderLines = state.orderLines.filter(l => l.productId !== id);
    renderOrder(); updateTotals();
}

function removeLine(id) { state.orderLines = state.orderLines.filter(l => l.productId !== id); renderOrder(); updateTotals(); }

function renderOrder() {
    const el = document.getElementById('posOrderLines');
    if (state.orderLines.length === 0) { el.innerHTML = '<div class="pos-empty-cart"><svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>No items yet</div>'; return; }
    let html = '';
    state.orderLines.forEach(l => {
        const subtotal = (l.price * l.qty).toFixed(2);
        html += '<div class="pos-order-line"><div class="pos-order-line-info"><div class="pos-order-line-name">' + escapeHtml(l.name) + '</div><div class="pos-order-line-qty-controls"><button onclick="changeQty(' + l.productId + ', -1)"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/></svg></button><span class="qty">' + l.qty + '</span><button onclick="changeQty(' + l.productId + ', 1)"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg></button></div></div><div class="pos-order-line-price">$' + subtotal + '</div><button class="pos-order-line-remove" onclick="removeLine(' + l.productId + ')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/></svg></button></div>';
    });
    el.innerHTML = html;
}

function updateTotals() {
    const subtotal = state.orderLines.reduce((sum, l) => sum + l.price * l.qty, 0);
    const tax = subtotal * 0.07;
    const total = subtotal + tax;
    document.getElementById('posSubtotal').textContent = '$' + subtotal.toFixed(2);
    document.getElementById('posTax').textContent = '$' + tax.toFixed(2);
    document.getElementById('posTotal').textContent = '$' + total.toFixed(2);
    const btn = document.getElementById('posPayBtn');
    if (state.orderLines.length > 0) { btn.disabled = false; btn.textContent = 'PAY $' + total.toFixed(2); }
    else { btn.disabled = true; btn.textContent = 'PAY $0.00'; }
}

function openPaymentModal() {
    const total = state.orderLines.reduce((sum, l) => sum + l.price * l.qty, 0) * 1.07;
    document.getElementById('modalTotal').textContent = '$' + total.toFixed(2);
    document.getElementById('payAmount').value = total.toFixed(2);
    document.getElementById('payChange').value = '$0.00';
    document.getElementById('payReference').value = '';
    document.getElementById('posPaymentModal').classList.add('open');
    document.getElementById('payAmount').focus();
    calcChange();
}

function closePaymentModal() { document.getElementById('posPaymentModal').classList.remove('open'); }

function selectPaymentMethod(btn, method) {
    document.querySelectorAll('.pos-payment-method-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    state.currentMethod = method;
}

function calcChange() {
    const total = state.orderLines.reduce((sum, l) => sum + l.price * l.qty, 0) * 1.07;
    const paid = parseFloat(document.getElementById('payAmount').value) || 0;
    document.getElementById('payChange').value = '$' + Math.max(paid - total, 0).toFixed(2);
}

async function confirmPayment() {
    const total = state.orderLines.reduce((sum, l) => sum + l.price * l.qty, 0) * 1.07;
    const paid = parseFloat(document.getElementById('payAmount').value) || 0;
    if (paid < total) { showToast('Insufficient payment amount', 'error'); return; }
    const orderData = {
        customer_name: document.getElementById('custName').value,
        partner_phone: document.getElementById('custPhone').value,
        partner_address: document.getElementById('custAddress').value,
        delivery_address: document.getElementById('custDelivery').value,
        channel: 'walkin',
        line_ids: state.orderLines.map(l => [0, 0, { product_id: l.productId, qty: l.qty, price_unit: l.price, discount: 0 }]),
        payment_ids: [[0, 0, { payment_method: state.currentMethod, amount: paid, reference: document.getElementById('payReference').value, state: 'paid' }]],
    };
    try {
        const resp = await fetch('/pos_lite/api/create_order', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(orderData) });
        const data = await resp.json();
        if (data.success) {
            showToast('Order ' + data.name + ' created!', 'success');
            state.orderLines = []; renderOrder(); updateTotals(); closePaymentModal();
        } else { showToast('Error: ' + data.error, 'error'); }
    } catch (e) { showToast('Failed to create order', 'error'); }
}

function escapeHtml(s) { if (!s) return ''; return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function showToast(msg, type) { const el = document.getElementById('posToast'); el.textContent = msg; el.className = 'pos-toast ' + type + ' show'; if (type !== 'warning') setTimeout(function() { el.classList.remove('show'); }, 3000); }
document.addEventListener('keydown', function(e) { if (e.key === 'Escape') closePaymentModal(); if (e.ctrlKey && e.key === 'p') { e.preventDefault(); openPaymentModal(); } });
document.addEventListener('DOMContentLoaded', initPos);
